fun solve(prices: Array<Long>, strategy: Array<Long>, k: Long): Long {
    val n = prices.size
    var maxProfit = 0L

    // Calculate the original profit
    var originalProfit = 0L
    for (i in 0 until n) {
        originalProfit += strategy[i] * prices[i]
    }
    maxProfit = originalProfit

    // Try to modify each possible subarray of length k
    for (i in 0 until n - k + 1) {
        var profitChange = 0L
        for (j in i until i + k) {
            when (strategy[j]) {
                -1L -> profitChange += prices[j] // Original was -1, now 0: change is +prices[j]
                1L -> profitChange -= prices[j] // Original was 1, now 0: change is -prices[j]
            }
        }
        // Update the maximum profit
        maxProfit = maxOf(maxProfit, originalProfit + profitChange)
    }

    return maxProfit
}
